func sidebarGroupI18nKey(g model.ChannelGroup) string {
	switch g.GroupID {
	case "favourites", "starred":
		return "drawer_starred"
	case "other":
		return "drawer_other"
	default:
		return ""
	}
}

func sidebarGroupTitle(p PageProps, g model.ChannelGroup) string {
	if key := sidebarGroupI18nKey(g); key != "" {
		return L(p, key, g.Title)
	}
	return g.Title
}

func sidebarGroupCount(g model.ChannelGroup) int {
	if g.Count > 0 {
		return g.Count
	}
	return len(g.Channels)
}

func sidebarGroupDeferred(g model.ChannelGroup) bool {
	if g.StarIcon || g.GroupID == "favourites" || g.GroupID == "starred" {
		return false
	}
	return g.Collapsed && sidebarGroupCount(g) > 0
}

